import base64
import json
from Crypto.Cipher import AES
from Crypto.Util.Padding import unpad


class Decryptor:
    def __init__(self):
        # 严格对应前端找出的 Key 和 IV，必须转换为 bytes 类型
        self.key = b'EB444973714E4A40876CE66BE45D5930'
        self.iv = b'B5A8904209931867'

    def decrypt(self, ciphertext: str) -> dict:
        """
        AES-CBC-PKCS7 解密响应体
        """
        try:
            # 1. Base64 解码密文
            encrypted_bytes = base64.b64decode(ciphertext)

            # 2. 初始化 AES 密码器 (CBC 模式)
            cipher = AES.new(self.key, AES.MODE_CBC, self.iv)

            # 3. 解密并去除 PKCS7 填充
            decrypted_bytes = unpad(cipher.decrypt(encrypted_bytes), AES.block_size)

            # 4. 转换为字符串并解析为 JSON 字典
            decrypted_str = decrypted_bytes.decode('utf-8')
            return json.loads(decrypted_str)

        except Exception as e:
            print(f"解密失败: {e}")
            return {}


# === 测试调用 ===
if __name__ == '__main__':
    # 替换为真实的 response.Data 密文
    test_ciphertext = ""
    decryptor = Decryptor()
    plaintext_json = decryptor.decrypt(test_ciphertext)
    print("解密成功，提取的明文数据：")
    print(json.dumps(plaintext_json, ensure_ascii=False, indent=2))